import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router";
import { useAuth } from "../Store/authStore";

import {
  articleCardClass,
  articleTitle,
  articleExcerpt,
  articleMeta,
  ghostBtn,
  loadingClass,
  errorClass,
  emptyStateClass,
  articleStatusActive,
  articleStatusDeleted,
} from "../styles/common";

function AuthorArticles() {
  const navigate = useNavigate();
  const user = useAuth((state) => state.currentUser);

  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  console.log("user in author profile",user)
  
  useEffect(() => {
    if (!user) return;

    const getAuthorArticles = async () => {
      setLoading(true);

      try {
        const res = await axios.get("/author-api/articles");
        setArticles(res.data.payload);
      } catch (err) {
        console.log(err);
        setError(err.response?.data?.message || "Failed to fetch articles");
      } finally {
        setLoading(false);
      }
    };

    getAuthorArticles();
  }, [user]);

  const openArticle = (article) => {
    navigate(`/article/${article._id}`, {
      state: article,
    });
  };

  const formatDate = (date) => {
    return new Date(date).toLocaleString("en-IN", {
      timeZone: "Asia/Kolkata",
      dateStyle: "medium",
    });
  };

  if (loading) return <p className={loadingClass}>Loading articles...</p>;
  if (error) return <p className={errorClass}>{error}</p>;

  if (articles.length === 0) {
    return <div className={emptyStateClass}>You haven't published any articles yet.</div>;
  }

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
      {articles.map((article) => (
        <div key={article._id} className={`${articleCardClass} relative flex flex-col`}>
          {/* Status Badge */}
          <span className={article.isArticleActive ? articleStatusActive : articleStatusDeleted}>
            {article.isArticleActive ? "ACTIVE" : "DELETED"}
          </span>

          <div className="flex flex-col gap-2">
            <p className={articleMeta}>{article.category}</p>

            <p className={articleTitle}>{article.title}</p>

            <p className={articleExcerpt}>{article.content.slice(0, 60)}...</p>
          </div>

          <button className={`${ghostBtn} mt-auto pt-4`} onClick={() => openArticle(article)}>
            Read Article →
          </button>
        </div>
      ))}
    </div>
  );
}

export default AuthorArticles;

import { useForm } from "react-hook-form";
import { useLocation, useNavigate, useParams } from "react-router";
import { useEffect } from "react";
import axios from "axios";


import {
  formCard,
  formTitle,
  formGroup,
  labelClass,
  inputClass,
  submitBtn,
  errorClass,
  articlePageWrapper,
} from "../styles/common";

function EditArticle() {
  const location = useLocation();
  const navigate = useNavigate();
  const { id } = useParams();

  const article = location.state;

  const {
    register,
    handleSubmit,
    setValue,
    formState: { errors },
  } = useForm();

  // prefill form
  useEffect(() => {
    if (!article) return;

     setValue("title", article.title);
     setValue("category", article.category);
     setValue("content", article.content);
  }, [article, setValue]);

  const updateArticle = async (modifiedArticle) => {

    //add articleId to modified article
    modifiedArticle.articleId=article._id;
    //make PUT req to update article
    let res=await axios.put("/author-api/articles",
      modifiedArticle,
      {withCredentials:true})
    //naviagte to articleById component
   if(res.status===200){
    navigate(`/article/${article._id}`,{state:res.data.payload})
   }
  };

  return (
    <div className={`${formCard} mt-10`}>
      <h2 className={formTitle}>Edit Article</h2>

      <form onSubmit={handleSubmit(updateArticle)}>
        {/* Title */}
        <div className={formGroup}>
          <label className={labelClass}>Title</label>

          <input className={inputClass} {...register("title", { required: "Title required" })} />

          {errors.title && <p className={errorClass}>{errors.title.message}</p>}
        </div>

        {/* Category */}
        <div className={formGroup}>
          <label className={labelClass}>Category</label>

          <select className={inputClass} {...register("category", { required: "Category required" })}>
            <option value="">Select category</option>
            <option value="technology">Technology</option>
            <option value="programming">Programming</option>
            <option value="ai">AI</option>
            <option value="web-development">Web Development</option>
          </select>

          {errors.category && <p className={errorClass}>{errors.category.message}</p>}
        </div>

        {/* Content */}
        <div className={formGroup}>
          <label className={labelClass}>Content</label>

          <textarea rows="14" className={inputClass} {...register("content", { required: "Content required" })} />

          {errors.content && <p className={errorClass}>{errors.content.message}</p>}
        </div>

        <button className={submitBtn}>Update Article</button>
      </form>
    </div>
  );
}

export default EditArticle;

import { useNavigate, NavLink } from "react-router";
import { useAuth } from "../Store/authStore.js";
import { pageWrapper, submitBtn, divider } from "../styles/common";


function UserProfile() {
  const currentUser = useAuth((state) => state.currentUser);
  const logout = useAuth((state) => state.logout);
  const navigate = useNavigate();


  const onLogout = async () => {
    await logout();
    navigate("/login");
  };

  return (
    <div className={pageWrapper}>
      <div className="bg-white border border-[#e8e8ed] rounded-3xl p-8 shadow-sm max-w-2xl mx-auto">
        <div className="flex items-center gap-6 mb-8">
          {currentUser?.profileImageURL ? (
            <img
              src={currentUser.profileImageURL}
              className="w-24 h-24 rounded-full object-cover border-4 border-[#0066cc]/10"
              alt="profile"
            />
          ) : (
            <div className="w-24 h-24 rounded-full bg-[#0066cc]/10 text-[#0066cc] flex items-center justify-center text-3xl font-bold">
              {currentUser?.firstName?.charAt(0).toUpperCase()}
            </div>
          )}

          <div>
            <h2 className="text-2xl font-bold text-[#1d1d1f] mb-1">
              {currentUser?.firstName} {currentUser?.lastName}
            </h2>
            <p className="text-[#86868b]">{currentUser?.email}</p>
            <span className="inline-block mt-2 px-3 py-1 bg-gray-100 text-xs font-semibold rounded-full uppercase tracking-wider text-gray-600">
              {currentUser?.role}
            </span>
          </div>
        </div>

        <div className={divider}></div>

        <div className="flex flex-col gap-4 mt-8">
          <NavLink to="/articles" className="text-center bg-[#f5f5f7] text-[#1d1d1f] px-6 py-3 rounded-xl font-medium hover:bg-gray-100 transition">
            Explore Articles
          </NavLink>

          <button
            className="w-full bg-[#ff3b30] text-white px-6 py-3 rounded-xl font-medium hover:bg-[#d62c23] transition shadow-md"
            onClick={onLogout}
          >
            Sign Out
          </button>
        </div>
      </div>


    </div>
  );
}

export default UserProfile;
